sys_script.script:
(function executeRule(current, previous) {

    var feeGR = new GlideRecord('x_1920777_campus_0_fee_record');

    if (feeGR.get(current.fee_record)) {

        var totalFee = parseFloat(feeGR.total_fee || 0);
        var existingPaid = parseFloat(feeGR.paid_amount || 0);
        var paymentAmount = parseFloat(current.amount_paid || 0);

        var newPaid = existingPaid + paymentAmount;
        var balance = totalFee - newPaid;

        if (balance < 0) {
            balance = 0;
        }

        feeGR.paid_amount = newPaid;
        feeGR.balance_amount = balance;

        if (newPaid <= 0) {
            feeGR.fee_status = 'pending';
        } else if (balance > 0) {
            feeGR.fee_status = 'partially_paid';
        } else {
            feeGR.fee_status = 'paid';
        }

        feeGR.update();

        if (!current.receipt_number) {
            current.receipt_number = 'REC-' + current.number;
            current.update();
        }
    }

})(current, previous);
